<span class="line">list <span class="token operator">??=</span> <span class="token keyword">new</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// C# 9+ 目标类型 new</span></span>
